export const CheckedChangeOutput = {
    args: {
        ...Default.args,
        checked: false,
    },
    render: (args) => ({
        props: {
            ...args,
            lastCheckedChange: null,
            onCheckedChange: function onCheckedChange(isChecked) {
                this["lastCheckedChange"] = isChecked;
            },
        },
        template: `
      <div style="display: grid; gap: 12px;">
        <rte-checkbox
          [id]="id"
          [label]="label"
          [value]="value"
          [indeterminate]="indeterminate"
          [description]="description"
          [showLabel]="showLabel"
          [disabled]="disabled"
          [error]="error"
          [errorMessage]="errorMessage"
          [readOnly]="readOnly"
          [checked]="checked"
          [tabindex]="tabindex"
          (checkedChange)="onCheckedChange($event)"
        />
        <div data-testid="checked">lastCheckedChange={{ lastCheckedChange }}</div>
      </div>
    `,
    }),
    play: async ({ canvasElement }) => {
        const canvas = within(canvasElement);
        const checkbox = canvas.getByRole("checkbox");
        const checked = canvas.getByTestId("checked");
        expect(checked).toHaveTextContent("lastCheckedChange=");
        await userEvent.click(checkbox);
        expect(checked).toHaveTextContent("lastCheckedChange=true");
    },
};
